import React, { useState } from "react";

// SVG que representa el ícono de la persona
const UserIcon = () => (
  <svg
    style={{ width: "50px", height: "50px", fill: "#333" }}
    viewBox="0 0 24 24"
  >
    <path d="M12 12c2.76 0 5-2.24 5-5S14.76 2 12 2 7 4.24 7 7s2.24 5 5 5zm0 2c-3.33 0-10 1.67-10 5v3h20v-3c0-3.33-6.67-5-10-5z" />
  </svg>
);

const InicioSesion = ({ onLogin, onClose }) => {
  const [usuario, setUsuario] = useState("");
  const [contrasena, setContrasena] = useState("");

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!usuario || !contrasena) {
      alert("Por favor, rellena todos los campos");
      return;
    }
    onLogin
      ? onLogin({ usuario, contrasena })
      : console.log({ usuario, contrasena });
  };

  // Contenedor fijo en la parte inferior, al centro
  const estilosContenedor = {
    position: "fixed",
    bottom: "20px",
    left: "50%",
    transform: "translateX(-50%)",
    width: "400px",
    maxWidth: "90%",
    backgroundColor: "rgba(245, 245, 220, 0.9)", // Beige con transparencia
    borderRadius: "15px",
    padding: "2rem 1.5rem 1.5rem 1.5rem",
    boxShadow: "0 2px 6px rgba(0,0,0,0.3)",
    fontFamily: "'Poppins', sans-serif", // Ajusta o cambia la fuente según prefieras
    zIndex: 9999,
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
  };

  // Ícono que sobresale por arriba del recuadro
  const estilosIcono = {
    position: "absolute",
    top: "-25px",
    left: "50%",
    transform: "translateX(-50%)",
    backgroundColor: "#fff",
    borderRadius: "50%",
    padding: "8px",
    boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
  };

  // Botón “X” para cerrar el recuadro
  const estilosCerrar = {
    position: "absolute",
    top: "10px",
    right: "10px",
    background: "none",
    border: "none",
    fontSize: "18px",
    cursor: "pointer",
    color: "#333",
  };

  // Título “Inicio de Sesión”
  const estilosTitulo = {
    marginTop: "30px", // Para dejar espacio al ícono
    marginBottom: "20px",
    fontSize: "20px",
    fontWeight: "bold",
    color: "#333",
    textAlign: "center",
  };

  // Inputs con borde gris, texto centrado
  const estilosInput = {
    width: "100%",
    margin: "10px 0",
    padding: "10px",
    fontSize: "16px",
    border: "1px solid #999",
    borderRadius: "8px",
    background: "none",
    textAlign: "center",
    outline: "none",
    color: "#333",
  };

  // Botón “Enviar” sin fondo ni borde
  const estilosBoton = {
    border: "none",
    background: "none",
    fontSize: "16px",
    marginTop: "20px",
    cursor: "pointer",
    color: "#333",
  };

  return (
    <div style={estilosContenedor}>
      {/* Ícono de la persona, con posición absoluta dentro del contenedor */}
      <div style={estilosIcono}>
        <UserIcon />
      </div>

      {/* Botón “X” para cerrar, si se pasa la función onClose */}
      {onClose && (
        <button style={estilosCerrar} onClick={onClose}>
          X
        </button>
      )}

      <div style={estilosTitulo}>Inicio de Sesión</div>

      <form onSubmit={handleSubmit} style={{ width: "100%" }}>
        <input
          type="text"
          placeholder="Usuario"
          value={usuario}
          onChange={(e) => setUsuario(e.target.value)}
          style={estilosInput}
        />
        <input
          type="password"
          placeholder="Contraseña"
          value={contrasena}
          onChange={(e) => setContrasena(e.target.value)}
          style={estilosInput}
        />
        <button type="submit" style={estilosBoton}>
          Enviar
        </button>
      </form>
    </div>
  );
};

export default InicioSesion;
